package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// It uses manual piping to ensure security and cross-platform compatibility.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// 1. Basic input validation
	if loadBalancerName == "" || outputFile == "" {
		return "", fmt.Errorf("loadBalancerName and outputFile cannot be empty")
	}

	// 2. Prepare the output file (equivalent to '>' redirection)
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file %q: %w", outputFile, err)
	}
	defer outFile.Close()

	// 3. Define the commands
	// aliyun slb DescribeLoadBalancers --LoadBalancerName NAME
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	// jq '.LoadBalancers.LoadBalancer[]'
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// 4. Capture stderr from both commands for debugging
	var stderr bytes.Buffer
	cmdAliyun.Stderr = &stderr
	cmdJq.Stderr = &stderr

	// 5. Create a pipe from aliyun's stdout to jq's stdin
	pipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}

	// 6. Connect the pipeline: aliyun -> jq -> file
	cmdJq.Stdin = pipe
	cmdJq.Stdout = outFile

	// 7. Start both processes
	if err := cmdAliyun.Start(); err != nil {
		return stderr.String(), fmt.Errorf("failed to start aliyun: %w", err)
	}
	if err := cmdJq.Start(); err != nil {
		return stderr.String(), fmt.Errorf("failed to start jq: %w", err)
	}

	// 8. Wait for the commands to complete.
	// We wait for cmdAliyun first; once it exits, it closes the pipe, 
	// which signals EOF to jq.
	errAliyun := cmdAliyun.Wait()
	errJq := cmdJq.Wait()

	// 9. Handle execution errors
	if errAliyun != nil {
		return stderr.String(), fmt.Errorf("aliyun command failed: %w", errAliyun)
	}
	if errJq != nil {
		return stderr.String(), fmt.Errorf("jq command failed: %w", errJq)
	}

	// Return any captured stderr (warnings) and a success status
	return stderr.String(), nil
}

func main() {
	// Example usage
	loadBalancerName := "test-slb"
	outputFile := "output.json"

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Printf("Error executing pipeline: %v\nDetails: %s\n", err, result)
		return
	}

	fmt.Printf("Successfully exported SLB info to %s\n", outputFile)
	if result != "" {
		fmt.Printf("Command Output/Warnings: %s\n", result)
	}
}

