// processes the output with jq, and saves it to the specified file.
// It uses os/exec to safely execute the command pipeline without shell injection.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	if loadBalancerName == "" || outputFile == "" {
		return "", fmt.Errorf("loadBalancerName and outputFile parameters are required")
	}

	// Prepare the aliyun command. 
	// Arguments are passed individually to prevent shell injection.
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Prepare the jq command.
	// Note: We do not include the single quotes used in shell commands.
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect aliyun's stdout to jq's stdin.
	pipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	cmdJq.Stdin = pipe

	// Open the output file for writing (this replaces the '>' shell redirection).
	// os.Create truncates the file if it already exists.
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()
	cmdJq.Stdout = outFile

	// Capture stderr from both commands to provide debugging information.
	var stderr bytes.Buffer
	cmdAliyun.Stderr = &stderr
	cmdJq.Stderr = &stderr

	// Start both commands.
	if err := cmdAliyun.Start(); err != nil {
		return stderr.String(), fmt.Errorf("failed to start aliyun command: %w", err)
	}
	if err := cmdJq.Start(); err != nil {
		return stderr.String(), fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for the commands to complete.
	// cmdAliyun.Wait() will close the pipe's write end, signaling EOF to jq.
	errAliyun := cmdAliyun.Wait()
	errJq := cmdJq.Wait()

	// Check for execution errors.
	if errAliyun != nil {
		return stderr.String(), fmt.Errorf("aliyun command failed: %w, stderr: %s", errAliyun, stderr.String())
	}
	if errJq != nil {
		return stderr.String(), fmt.Errorf("jq command failed: %w, stderr: %s", errJq, stderr.String())
	}

	// The stdout of the pipeline is in the file, so we return the captured stderr/logs.
	return stderr.String(), nil
}

func main() {
	// Example usage
