package main

import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the following pipeline:
// aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > output.json
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// 1. Prepare the commands
	// aliyun slb DescribeLoadBalancers --LoadBalancerName NAME
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// jq '.LoadBalancers.LoadBalancer[]'
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// 2. Prepare the output file redirection ( > output.json )
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()
	jqCmd.Stdout = outFile

	// 3. Create a pipe to connect aliyun's stdout to jq's stdin
	// This implements the "|" part of the command
	pr, pw := io.Pipe()
	aliyunCmd.Stdout = pw
	jqCmd.Stdin = pr

	// Capture stderr to provide meaningful error messages if execution fails
	var aliyunStderr, jqStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stderr = &jqStderr

	// 4. Execute the commands
	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		pw.Close()
		return "", fmt.Errorf("failed to start aliyun: %w", err)
	}

	// Start jq command
	if err := jqCmd.Start(); err != nil {
		pw.Close()
		return "", fmt.Errorf("failed to start jq: %w", err)
	}

	// Wait for aliyun to finish in a separate routine to manage the pipe lifecycle
	aliyunErrChan := make(chan error, 1)
	go func() {
		err := aliyunCmd.Wait()
		// Closing the PipeWriter sends an EOF to the PipeReader (jq's stdin)
		pw.Close()
		aliyunErrChan <- err
	}()

	// Wait for jq to finish processing the piped data
	jqErr := jqCmd.Wait()
	aliyunErr := <-aliyunErrChan

	// 5. Handle potential errors from either command
	if aliyunErr != nil {
		return "", fmt.Errorf("aliyun command failed: %v, stderr: %s", aliyunErr, aliyunStderr.String())
	}
	if jqErr != nil {
		return "", fmt.Errorf("jq command failed: %v, stderr: %s", jqErr, jqStderr.String())
	}

	return fmt.Sprintf("Successfully exported SLB information for '%s' to '%s'", loadBalancerName, outputFile), nil
}

func main() {
	// Example parameters
	loadBalancerName := "my-test-slb"
	outputFile := "output.json"

	// Execute the function
	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Println(result)
}

