// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// It implements the pipeline: aliyun | jq > outputFile
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// 1. Prepare the output file
	// os.Create truncates the file if it already exists, matching the '>' behavior.
	out, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer out.Close()

	// 2. Define the commands
	// Note: We pass arguments directly to exec.Command, avoiding shell injection.
	// Filter quotes are removed because they are shell-specific grouping characters.
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// 3. Capture stderr from both commands
	// Since stdout is redirected to a file, stderr is the primary source of execution feedback.
	var stderr bytes.Buffer
	cmdAliyun.Stderr = &stderr
	cmdJq.Stderr = &stderr

	// 4. Connect the pipeline: aliyun.stdout -> jq.stdin
	pipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	cmdJq.Stdin = pipe

	// 5. Connect the final output: jq.stdout -> file
	cmdJq.Stdout = out

	// 6. Start both processes
	if err := cmdAliyun.Start(); err != nil {
		return stderr.String(), fmt.Errorf("failed to start aliyun: %w", err)
	}
	if err := cmdJq.Start(); err != nil {
		return stderr.String(), fmt.Errorf("failed to start jq: %w", err)
	}

	// 7. Wait for commands to complete
	// Wait() for cmdAliyun will close the pipe when the process exits, signaling EOF to jq.
	if err := cmdAliyun.Wait(); err != nil {
		return stderr.String(), fmt.Errorf("aliyun execution failed: %w", err)
	}

	if err := cmdJq.Wait(); err != nil {
		return stderr.String(), fmt.Errorf("jq execution failed: %w", err)
	}

	// Return any captured stderr (warnings/info) or an empty string on clean success
	return stderr.String(), nil
}

func main() {
	// Example usage
	loadBalancerName := "test-lb"
	outputFile := "output.json"

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\nCommand Output: %s\n", err, result)
		os.Exit(1)
	}

	if result != "" {
		fmt.Printf("Command executed with output: %s\n", result)
	}
	fmt.Printf("Successfully exported SLB info to %s\n", outputFile)
}

