// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// This implementation uses manual piping with os/exec to avoid shell injection
// vulnerabilities and provide robust error handling.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	if loadBalancerName == "" || outputFile == "" {
		return "", fmt.Errorf("loadBalancerName and outputFile parameters cannot be empty")
	}

	// 1. Prepare the commands. 
	// Arguments are passed directly to the executable, bypassing the shell 
	// and preventing shell injection attacks.
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// 2. Capture stderr separately for each command to help with diagnostics.
	var stderrAliyun, stderrJq bytes.Buffer
	cmdAliyun.Stderr = &stderrAliyun
	cmdJq.Stderr = &stderrJq

	// 3. Create the output file (equivalent to '>' redirection in shell).
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// 4. Set up the pipeline: aliyun stdout -> jq stdin; jq stdout -> file.
	cmdJq.Stdout = outFile
	pipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	cmdJq.Stdin = pipe

	// 5. Start both commands.
	if err := cmdAliyun.Start(); err != nil {
		return stderrAliyun.String(), fmt.Errorf("failed to start aliyun command: %w", err)
	}
	if err := cmdJq.Start(); err != nil {
		return stderrJq.String(), fmt.Errorf("failed to start jq command: %w", err)
	}

	// 6. Wait for the commands to complete.
	// cmdAliyun.Wait() will close the pipe when the process exits, 
	// which sends an EOF signal to the jq process.
	errAliyun := cmdAliyun.Wait()
	errJq := cmdJq.Wait()

	// 7. Combine stderr output for the return result.
	combinedStderr := stderrAliyun.String() + stderrJq.String()

	// 8. Check for execution errors.
