package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// It returns the combined stderr output of the commands and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	if loadBalancerName == "" || outputFile == "" {
		return "", fmt.Errorf("loadBalancerName and outputFile must not be empty")
	}

	// 1. Prepare the commands.
	// We use separate arguments instead of a shell string to prevent shell injection.
	// aliyun slb DescribeLoadBalancers --LoadBalancerName NAME
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	// jq '.LoadBalancers.LoadBalancer[]'
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// 2. Capture stderr from both commands to provide detailed error reporting.
	var stderrAliyun, stderrJq bytes.Buffer
	cmdAliyun.Stderr = &stderrAliyun
	cmdJq.Stderr = &stderrJq

	// 3. Create a pipe to connect aliyun's stdout to jq's stdin.
	pipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}

	// 4. Open the output file for the final redirected result.
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// 5. Connect the pipeline.
	cmdJq.Stdin = pipe
	cmdJq.Stdout = outFile

	// 6. Start the commands.
	if err := cmdAliyun.Start(); err != nil {
		return stderrAliyun.String(), fmt.Errorf("failed to start aliyun: %w", err)
	}
	if err := cmdJq.Start(); err != nil {
		return stderrJq.String(), fmt.Errorf("failed to start jq: %w", err)
	}

	// 7. Wait for completion.
	// cmdAliyun.Wait() will close the pipe once the process exits, sending EOF to jq.
	errAliyun := cmdAliyun.Wait()
	errJq := cmdJq.Wait()

	// 8. Combine stderr outputs for the return value.
	var combinedStderr string
	if stderrAliyun.Len() > 0 {
		combinedStderr += "aliyun stderr: " + stderrAliyun.String()
	}
	if stderrJq.Len() > 0 {
		combinedStderr += "jq stderr: " + stderrJq.String()
	}

	// 9. Check for execution errors.
	if errAliyun != nil {
		return combinedStderr, fmt.Errorf("aliyun execution failed: %w", errAliyun)
	}
	if errJq != nil {
		return combinedStderr, fmt.Errorf("jq execution failed: %w", errJq)
	}

	return combinedStderr, nil
}

func main() {
	// Example usage
	loadBalancerName := "my-test-slb"
	outputFile := "slb_info.json"

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		if result != "" {
			fmt.Fprintf(os.Stderr, "Command Output: %s\n", result)
		}
		os.Exit(1)
	}

	fmt.Printf("Successfully exported SLB '%s' information to '%s'\n", loadBalancerName, outputFile)
}

