package main

import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// It uses native os/exec piping instead of shell execution to prevent shell injection.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Prepare the commands
	// Command 1: aliyun slb DescribeLoadBalancers --LoadBalancerName <NAME>
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Command 2: jq '.LoadBalancers.LoadBalancer[]'
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Capture stderr from both commands to provide detailed error information
	var stderrBuf bytes.Buffer
	cmdAliyun.Stderr = &stderrBuf
	cmdJq.Stderr = &stderrBuf

	// Create the output file where the final formatted JSON will be saved
	f, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer f.Close()

	// Redirect the stdout of the jq command to the file
	cmdJq.Stdout = f

	// Create a synchronous pipe to connect aliyun's stdout to jq's stdin
	// This mimics the '|' shell operator
	pr, pw := io.Pipe()
	cmdAliyun.Stdout = pw
	cmdJq.Stdin = pr

	// Start the aliyun command
	if err := cmdAliyun.Start(); err != nil {
		pw.Close()
		return stderrBuf.String(), fmt.Errorf("failed to start aliyun: %w", err)
	}

	// Start the jq command
	if err := cmdJq.Start(); err != nil {
		pw.Close()
		return stderrBuf.String(), fmt.Errorf("failed to start jq: %w", err)
	}

	// Wait for the aliyun command to finish.
	// We must close the pipe's writer (pw) after cmdAliyun finishes 
	// so that the jq command (the reader) receives an EOF and can terminate.
	errAliyun := cmdAliyun.Wait()
	pw.Close()

	// Wait for the jq command to finish
	errJq := cmdJq.Wait()

	// Evaluate execution results
	if errAliyun != nil {
		return stderrBuf.String(), fmt.Errorf("aliyun command failed: %w, stderr: %s", errAliyun, stderrBuf.String())
	}
	if errJq != nil {
		return stderrBuf.String(), fmt.Errorf("jq command failed: %w, stderr: %s", errJq, stderrBuf.String())
	}

	// Return any captured stderr (usually empty on success)
	return stderrBuf.String(), nil
}

func main() {
	// Example usage
	loadBalancerName := "example-slb"
	outputFile := "slb_output.json"

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Printf("Error executing command: %v\n", err)
		if result != "" {
			fmt.Printf("Command Output/Stderr: %s\n", result)
		}
		return
	}

