// It uses os/exec safely to prevent shell injection by avoiding shell interpretation.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// 1. Prepare the 'aliyun' command. 
	// Arguments are passed individually, which prevents shell injection.
