// QuerySLBAndExport executes the command pipeline:
// aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > output.json
// It uses the os/exec package to handle process execution and manual piping.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// 1. Create the output file (equivalent to '>' in shell)
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// 2. Define the individual commands
	// Command: aliyun slb DescribeLoadBalancers --LoadBalancerName <NAME>
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	// Command: jq '.LoadBalancers.LoadBalancer[]'
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// 3. Capture stderr from both commands to provide meaningful error results
	var stderr bytes.Buffer
	cmdAliyun.Stderr = &stderr
	cmdJq.Stderr = &stderr

	// 4. Create a pipe to connect aliyun's stdout to jq's stdin (equivalent to '|' in shell)
	stdoutPipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}

	// 5. Setup IO redirection
	cmdJq.Stdin = stdoutPipe // jq reads from aliyun's output
	cmdJq.Stdout = outFile   // jq writes to the file

	// 6. Start both processes
	if err := cmdAliyun.Start(); err != nil {
		return stderr.String(), fmt.Errorf("failed to start aliyun command: %w", err)
	}

	if err := cmdJq.Start(); err != nil {
		return stderr.String(), fmt.Errorf("failed to start jq command: %w", err)
	}

	// 7. Wait for the aliyun command to finish.
	// Calling Wait() on cmdAliyun will close stdoutPipe when the process exits, 
	// which sends an EOF to jq's stdin.
	if err := cmdAliyun.Wait(); err != nil {
		return stderr.String(), fmt.Errorf("aliyun command execution failed: %w", err)
	}

	// 8. Wait for the jq command to finish processing the data.
	if err := cmdJq.Wait(); err != nil {
		return stderr.String(), fmt.Errorf("jq command execution failed: %w", err)
	}

	return fmt.Sprintf("Successfully exported SLB info for '%s' to '%s'", loadBalancerName, outputFile), nil
}

func main() {
	// Example parameters
	lbName := "my-load-balancer"
	outPath := "output.json"

	fmt.Printf("Executing query for SLB: %s...\n", lbName)

	result, err := QuerySLBAndExport(lbName, outPath)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Execution Error: %v\n", err)
		if result != "" {
			fmt.Fprintf(os.Stderr, "Command Output: %s\n", result)
		}
		os.Exit(1)
	}

	fmt.Println(result)
}

