// QuerySLBAndExport executes the aliyun slb command, pipes the output through jq,
// and exports the result to the specified output file.
//
// Equivalent to:
// aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > output.json
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// 1. Prepare the aliyun command
	// Note: We pass arguments directly to exec.Command, so shell escaping is not needed for the name.
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// 2. Prepare the jq command
	// The filter is passed as a single argument.
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// 3. Create the stdout pipe from aliyun to jq
	pipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	cmdJq.Stdin = pipe

	// 4. Prepare the output file (equivalent to '>' redirection)
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file '%s': %w", outputFile, err)
	}
	defer outFile.Close()
	cmdJq.Stdout = outFile

	// 5. Capture stderr for debugging purposes
	var stderrAliyun bytes.Buffer
	var stderrJq bytes.Buffer
	cmdAliyun.Stderr = &stderrAliyun
	cmdJq.Stderr = &stderrJq

	// 6. Start the commands
	if err := cmdAliyun.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}
	if err := cmdJq.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// 7. Wait for aliyun to complete
	errAliyun := cmdAliyun.Wait()

	// Close the pipe manually to signal EOF to jq
	// This ensures jq doesn't hang if aliyun exits
	pipe.Close()

	// 8. Wait for jq to complete
	errJq := cmdJq.Wait()

	// 9. Process errors
	if errAliyun != nil {
		return stderrAliyun.String(), fmt.Errorf("aliyun command execution failed: %w", errAliyun)
	}
	if errJq != nil {
		return stderrJq.String(), fmt.Errorf("jq command execution failed: %w", errJq)
	}

	return fmt.Sprintf("Successfully exported SLB '%s' to '%s'", loadBalancerName, outputFile), nil
}

