package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes a command pipeline to query Alibaba Cloud SLB information
// and formats the output using jq before saving it to a file.
//
// Equivalent bash command:
// aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > output.json
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// 1. Prepare the 'aliyun' command
	// aliyun slb DescribeLoadBalancers --LoadBalancerName <NAME>
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// 2. Prepare the 'jq' command
	// jq '.LoadBalancers.LoadBalancer[]'
	// Note: We pass the filter string directly; os/exec handles arguments without needing shell quotes.
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// 3. Set up stderr buffers to capture detailed error messages from both commands
	var stderrAliyun, stderrJq bytes.Buffer
	cmdAliyun.Stderr = &stderrAliyun
	cmdJq.Stderr = &stderrJq

	// 4. Create a pipe to connect aliyun's stdout to jq's stdin
	pipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	cmdJq.Stdin = pipe

	// 5. Open/Create the output file to capture jq's stdout
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file '%s': %w", outputFile, err)
	}
	defer outFile.Close()
	cmdJq.Stdout = outFile

	// 6. Start the aliyun command
	if err := cmdAliyun.Start(); err != nil {
		return stderrAliyun.String(), fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// 7. Start the jq command
	if err := cmdJq.Start(); err != nil {
		return stderrJq.String(), fmt.Errorf("failed to start jq command: %w", err)
	}

	// 8. Wait for the aliyun command to finish.
	// Calling Wait() on cmdAliyun will close the pipe once the process exits, 
	// which sends an EOF signal to the jq process.
	errAliyun := cmdAliyun.Wait()

	// 9. Wait for the jq command to finish processing the input.
	errJq := cmdJq.Wait()

	// 10. Handle execution errors
	if errAliyun != nil {
		return stderrAliyun.String(), fmt.Errorf("aliyun execution error: %w", errAliyun)
	}
	if errJq != nil {
		return stderrJq.String(), fmt.Errorf("jq execution error: %w", errJq)
	}

	return fmt.Sprintf("Successfully exported SLB information for '%s' to %s", loadBalancerName, outputFile), nil
}

func main() {
	// Example usage
	// Replace "my-load-balancer" with an actual SLB name and "output.json" with the desired path.
	loadBalancerName := "my-load-balancer"
	outputFile := "output.json"

	fmt.Printf("Executing query for SLB: %s...\n", loadBalancerName)

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error occurred: %v\n", err)
		if result != "" {
			fmt.Fprintf(os.Stderr, "Command Stderr: %s\n", result)
		}
		os.Exit(1)
	}

	fmt.Println(result)
}

